#!/usr/bin/env node
// Copies authhero messages JSON files into src/i18n/messages/ and generates an index.ts

const { readFileSync, writeFileSync, readdirSync, mkdirSync } = require("fs");
const { join } = require("path");

const srcDir = join(__dirname, "../../../packages/authhero/messages");
const destDir = join(__dirname, "../src/i18n/messages");

mkdirSync(destDir, { recursive: true });

const files = readdirSync(srcDir).filter((f) => f.endsWith(".json"));
const langs = [];

for (const file of files) {
  const lang = file.replace(".json", "");
  langs.push(lang);
  const content = readFileSync(join(srcDir, file), "utf-8");
  writeFileSync(join(destDir, file), content);
}

// Generate index.ts
const imports = langs
  .map((lang) => `import ${lang}Messages from "./${lang}.json";`)
  .join("\n");

const mapEntries = langs.map((lang) => `  ${lang}: ${lang}Messages`).join(",\n");

const indexContent = `// Auto-generated by scripts/copy-messages.js — do not edit manually
${imports}

export const messages: Record<string, Record<string, string>> = {
${mapEntries},
};
`;

writeFileSync(join(destDir, "index.ts"), indexContent);

console.log(`Copied ${langs.length} language files to src/i18n/messages/`);
